using Microsoft.UI.Xaml;\nusing Microsoft.UI.Xaml.Controls;\nusing PartTracker.Services;\nusing Serilog;\n\nnamespace PartTracker.Views\n{\n    public sealed partial class LoginPage : Window\n    {\n        private readonly DatabaseService _db;\n        private readonly AuthService _auth;\n        private readonly ILogger _logger;\n\n        public LoginPage()\n        {\n            InitializeComponent();\n            _db = new DatabaseService();\n            _auth = new AuthService(_db);\n            _logger = new LoggerConfiguration()\n                .WriteTo.File(\"logs/ui.log\", rollingInterval: RollingInterval.Day)\n                .CreateLogger();\n        }\n\n        private async void OnLoginClick(object sender, RoutedEventArgs e)\n        {\n            try\n            {\n                LoadingRing.IsActive = true;\n                LoginButton.IsEnabled = false;\n                ErrorMessage.Text = \"\";\n\n                string username = UsernameInput.Text?.Trim() ?? \"\";\n                string password = PasswordInput.Password ?? \"\";\n\n                if (string.IsNullOrEmpty(username) || string.IsNullOrEmpty(password))\n                {\n                    ErrorMessage.Text = \"Vyplňte prosím ID a heslo\";\n                    return;\n                }\n\n                var (success, user) = await _auth.LoginAsync(username, password);\n\n                if (!success || user == null)\n                {\n                    ErrorMessage.Text = \"Nesprávné ID nebo heslo\";\n                    _logger.Warning($\"Failed login attempt for {username}\");\n                    return;\n                }\n\n                _logger.Information($\"User {username} ({user.Role}) logged in\");\n\n                if (user.Role == \"Admin\")\n                {\n                    var adminPage = new AdminPage(_db);\n                    adminPage.Activate();\n                }\n                else\n                {\n                    var searchPage = new SearchPage(_db, user);\n                    searchPage.Activate();\n                }\n\n                this.Close();\n            }\n            catch (Exception ex)\n            {\n                ErrorMessage.Text = $\"Chyba: {ex.Message}\";\n                _logger.Error($\"Login error: {ex.Message}\");\n            }\n            finally\n            {\n                LoadingRing.IsActive = false;\n                LoginButton.IsEnabled = true;\n            }\n        }\n    }\n}